// Expecting input like: { content: [ { text, offset, duration, ... }, ... ] }

function toHMS(seconds) {
  const sec = Math.floor(seconds);
  const h = Math.floor(sec / 3600);
  const m = Math.floor((sec % 3600) / 60);
  const s = sec % 60;

  const hh = h > 0 ? String(h).padStart(2, '0') + ':' : '';
  const mm = String(m).padStart(2, '0');
  const ss = String(s).padStart(2, '0');

  return hh + mm + ':' + ss;
}

const input = $json;
const chunks = input.content || [];

const out = chunks.map(chunk => {
  const startSec = chunk.offset / 1000;
  const endSec = (chunk.offset + chunk.duration) / 1000;

  return {
    text: chunk.text,
    offset_ms: chunk.offset,
    duration_ms: chunk.duration,
    start_seconds: startSec,
    end_seconds: endSec,
    start_hms: toHMS(startSec),
    end_hms: toHMS(endSec),
  };
});

// Return as items for downstream nodes
return out.map(o => ({ json: o }));

// Gather all incoming items
const items = $input.all();

// Map to segments while excluding offset_ms and duration_ms
const segments = items.map(item => {
  const { offset_ms, duration_ms, ...rest } = item.json;
  return rest;
});

return [
  {
    json: {
      segments
    }
  }
];
